from flask import Flask, request, jsonify
from pymemcache.client.base import Client
import sqlite3

app = Flask(__name__)
memcached_client = Client(('localhost', 11211))

@app.route('/db_query', methods=['GET'])
def db_query():
    query_key = 'db_query'
    result = memcached_client.get(query_key)
    if result is None:
        conn = sqlite3.connect('test.db')
        cursor = conn.cursor()
        result = cursor.execute("SELECT * FROM users").fetchall()
        # Cache the query result with TTL of 60 seconds
        memcached_client.set(query_key, result, expire=60)
        conn.close()
    return jsonify(result)

@app.route('/api', methods=['GET'])
def api():
    api_key = 'api'
    result = memcached_client.get(api_key)
    if result is None:
        # Generate API response (mock data)
        result = {'data': [1, 2, 3, 4]}
        # Cache the API response with TTL of 30 seconds
        memcached_client.set(api_key, result, expire=30)
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)